import{_ as t,c as a,o as i,aj as n}from"./chunks/framework.guNMSiFm.js";const u=JSON.parse('{"title":"Event Trigger Example","description":"","frontmatter":{},"headers":[],"relativePath":"blockchain/trigger-examples.md","filePath":"blockchain/trigger-examples.md","lastUpdated":1777621302000}'),s={name:"blockchain/trigger-examples.md"};function r(o,e,c,l,d,p){return i(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="event-trigger-example" tabindex="-1">Event Trigger Example <a class="header-anchor" href="#event-trigger-example" aria-label="Permalink to &quot;Event Trigger Example&quot;">​</a></h1><p>This example describes the shape of an event trigger in the current Iroha model without depending on older <code>account@domain</code> or <code>asset#domain</code> literals.</p><p>Suppose a network has:</p><ul><li>a canonical account controlled by Alice&#39;s key</li><li>a canonical account controlled by the Mad Hatter&#39;s key</li><li>an asset definition projected as <code>tea</code> under <code>wonderland.universal</code></li><li>a balance of that asset held by each account</li></ul><p>The goal is to register a trigger that observes Alice&#39;s tea balance and submits a transfer from the Mad Hatter account when the matching data event is emitted.</p><h2 id="_1-prepare-accounts-and-assets" tabindex="-1">1. Prepare accounts and assets <a class="header-anchor" href="#_1-prepare-accounts-and-assets" aria-label="Permalink to &quot;1. Prepare accounts and assets&quot;">​</a></h2><p>Register the participating accounts and the asset definition first. In current Iroha, account IDs come from account controllers, while projected domains use <code>domain.dataspace</code> form:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>domain: wonderland.universal</span></span>
<span class="line"><span>asset definition projection: tea in wonderland.universal</span></span>
<span class="line"><span>holder accounts: AccountId(controller=alice_key), AccountId(controller=mad_hatter_key)</span></span></code></pre></div><p>The asset definition still has a canonical opaque address. Store or query that address after registration and use it in the trigger action.</p><h2 id="_2-choose-the-trigger-authority" tabindex="-1">2. Choose the trigger authority <a class="header-anchor" href="#_2-choose-the-trigger-authority" aria-label="Permalink to &quot;2. Choose the trigger authority&quot;">​</a></h2><p>Set the trigger&#39;s technical account to a dedicated account when possible. A dedicated account makes it clear which permissions are required for trigger execution and avoids coupling the trigger to an operator&#39;s personal signing key.</p><p>The technical account must already exist and must have permission to submit the instructions in the trigger executable.</p><h2 id="_3-define-the-executable" tabindex="-1">3. Define the executable <a class="header-anchor" href="#_3-define-the-executable" aria-label="Permalink to &quot;3. Define the executable&quot;">​</a></h2><p>The executable is the instruction sequence the trigger submits when the event filter matches. For this example, it contains one transfer:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Transfer(</span></span>
<span class="line"><span>  source = AssetId(tea_definition, mad_hatter_account),</span></span>
<span class="line"><span>  value = Numeric(1),</span></span>
<span class="line"><span>  destination = AssetId(tea_definition, alice_account)</span></span>
<span class="line"><span>)</span></span></code></pre></div><p>Use the SDK&#39;s current typed builders for the final transaction payload. Avoid hard-coding old textual IDs in trigger code; parse or query canonical IDs before building the executable.</p><h2 id="_4-define-the-event-filter" tabindex="-1">4. Define the event filter <a class="header-anchor" href="#_4-define-the-event-filter" aria-label="Permalink to &quot;4. Define the event filter&quot;">​</a></h2><p>Use a data-event filter that narrows events to the object you care about:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>EventFilterBox::Data(</span></span>
<span class="line"><span>  DataEventFilter for asset changes involving</span></span>
<span class="line"><span>  AssetId(tea_definition, alice_account)</span></span>
<span class="line"><span>)</span></span></code></pre></div><p>Keep filters as specific as practical. An <code>AcceptAll</code> filter is useful for debugging, but it makes every matching event pay the cost of trigger evaluation.</p><h2 id="_5-register-the-trigger" tabindex="-1">5. Register the trigger <a class="header-anchor" href="#_5-register-the-trigger" aria-label="Permalink to &quot;5. Register the trigger&quot;">​</a></h2><p>Register the trigger with:</p><ul><li>a stable <code>TriggerId</code></li><li>the executable instruction sequence</li><li><code>Repeats::Indefinitely</code> or <code>Repeats::Exactly(n)</code></li><li>the technical account</li><li>the event filter</li><li>optional metadata</li></ul><p>Trigger registration itself is a normal transaction, so the registering account needs permission to register triggers. The technical account needs the permissions required by the trigger executable.</p><h2 id="execution-order" tabindex="-1">Execution order <a class="header-anchor" href="#execution-order" aria-label="Permalink to &quot;Execution order&quot;">​</a></h2><p>When a block executes:</p><ol><li>Normal transaction instructions run first.</li><li>Data events produced by those instructions are collected.</li><li>Triggers whose filters match those events are scheduled.</li><li>Trigger-produced effects are handled in the block execution pipeline without allowing unbounded recursive trigger execution.</li></ol><p>If a trigger uses <code>Repeats::Exactly(n)</code>, register a new trigger when the count is exhausted and the same behavior is needed again.</p>`,28)])])}const g=t(s,[["render",r]]);export{u as __pageData,g as default};
